form:Form.form:Scripts:
		var arrFILTER;
var arrSELECTED;


//Actualiza la lista con el nuevo ARRAY
function refreshSelected()
{              
 	var page=Ctrl("listSELECTED").Page;
	Ctrl("listSELECTED").IDs=arrSELECTED;
	Ctrl("listSELECTED").ResetSQL();
	Ctrl("listSELECTED").GotoPage(page);

	Ctrl("incluidos").SetXValue("Legajos Incluidos: "+arrSELECTED.length);

	enable_buttons();
}


function enable_custom_buttons()
{
}


function internal_filter()
{  
  var auxArr;
	auxArr = exec_qry();
	if (auxArr==null) return;  

	remove(auxArr, arrSELECTED);

	intersect(arrFILTER, auxArr);	
	refreshList();
}

function internal_find()
{ 
  var auxArr, auxArr2;
	auxArr = exec_qry();
	if (auxArr==null) return;  

	auxArr2=new Array();
	copiar(auxArr2, auxArr);

	//Obtiene los Elementos en Comun.
	intersect(auxArr , arrFILTER);
	intersect(auxArr2, arrSELECTED);		

	if (auxArr.length==0 && auxArr2.length==0) 
	{
		alert("No se encontro ningun registro.");
		return;
	}

	if (auxArr.length!=0)
		Ctrl("listFILTER").SetXValue(auxArr[0]);

	if (auxArr2.length!=0)
		Ctrl("listSELECTED").SetXValue(auxArr2[0]);
}

function ONLOAD()
{
	var t, ROW, VALUES;
	arrFILTER = new Array();
	arrSELECTED = new Array();

	//Valores Iniciales
	for (t=0; t<Ctrl("arrSELECTED").CountRow(); t++)
	{
		ROW=Ctrl("arrSELECTED").GetRow(t);
		VALUES=ROW.GetAttr("VALUES").split(",");
		for (d=0; d<VALUES.length; d++)
			if (VALUES[d]!="")
				arrSELECTED.push(VALUES[d]);
	} 

	refreshSelected();
	refreshList();
}

function ONLOAD_custom()
{
}        

function FillArray(numByRow)
{
	var t,n,values,sep,row,p;

	Ctrl("arrSELECTED").DelAllRow(); 

	values=""; sep="";
	for (t=0,n=0,p=0; t<arrSELECTED.length; t++, n++)
	{
		if (n>=numByRow)
		{              
			p++;
			row=Ctrl("arrSELECTED").AddRow()
			row.SetAttr("id", p);
			row.SetAttr("VALUES", values);
			values=""; sep=""; n=0;
		}                  

		values+=sep+arrSELECTED[t];
		sep=",";
	}
	if (values!="") 
	{      
		p++;
		row=Ctrl("arrSELECTED").AddRow()
		row.SetAttr("id", p);
		row.SetAttr("VALUES", values);
	}

}

function ADD()
{                              
	var X, val;

	val=Ctrl("listFILTER").GetXValue();
	for (X=0; X<arrFILTER.length; X++) 
	if (arrFILTER[X]==val)
	{
		arrFILTER.splice(X,1);

		if (X<arrFILTER.length-1)
			Ctrl("listFILTER").SetXValue(arrFILTER[X]);
		else                                    
		if (arrFILTER.length>0)    
			Ctrl("listFILTER").SetXValue(arrFILTER[arrFILTER.length-1]);
		else
			Ctrl("listFILTER").SetXValue("");

		refreshList();
		break;
	}
	arrSELECTED.push(val);
	refreshSelected();
	Ctrl("listSELECTED").SetXValue(val);
}

function ADD_ALL()
{                 
	Ctrl("listFILTER").SetXValue("");
	Ctrl("arrSELECTED").SetXValue("");

	union(arrSELECTED, arrFILTER);
	arrFILTER=new Array();
	refreshSelected();
	refreshList();
}

function DEL()
{              
	var X, val;

	val=Ctrl("listSELECTED").GetXValue();
	for (X=0; X<arrSELECTED.length; X++) 
	if (arrSELECTED[X]==val)
	{
		arrSELECTED.splice(X,1);

		if (X<arrSELECTED.length-1)
			Ctrl("listSELECTED").SetXValue(arrSELECTED[X]);
		else                                    
		if (arrSELECTED.length>0)    
			Ctrl("listSELECTED").SetXValue(arrSELECTED[arrSELECTED.length-1]);
		else
			Ctrl("listSELECTED").SetXValue("");

		refreshSelected();
		break;
	}
	arrFILTER.push(val);
	refreshList();
	Ctrl("listFILTER").SetXValue(val);
}

function DEL_ALL()
{
	Ctrl("listFILTER").SetXValue("");
	Ctrl("arrSELECTED").SetXValue("");

	union(arrFILTER, arrSELECTED);
	arrSELECTED=new Array();
	refreshSelected();
	refreshList();
}

//Elimino iten del FILTRO
function delSELECTED()
{                      
	var listID=Ctrl("listSELECTED").GetXValue();

	for (var X=0; X<arrSELECTED.length; X++)
	if (arrSELECTED[X]==listID)
	{                        
		arrSELECTED.splice(X,1);

		if (X<arrSELECTED.length-1)
			Ctrl("listSELECTED").SetXValue(arrSELECTED[X]);
		else                                    
		if (arrSELECTED.length>0)    
			Ctrl("listSELECTED").SetXValue(arrSELECTED[arrSELECTED.length-1]);
		else
			Ctrl("listSELECTED").SetXValue("");
		break;
	}

	refreshSelected();
}

//Limpio la Lista del FILTRO
function clearSELECTED()
{  
	arrSELECTED=new Array();	
	refreshSelected();        

	Ctrl("listSELECTED").SetXValue("");
}

function ACCEPT()
{
	Ctrl("main").DoEvent("ACCEPT");
}

function CANCEL()
{
	Ctrl("main").DoEvent("CANCEL");
}
